await import('https://cdn.jsdelivr.net/npm/@vaadin/avatar-group@25.2.5/+esm');
await customElements.whenDefined('vaadin-avatar-group');
const host = document.createElement('div'); host.style.cssText = 'display:block;width:100%';
const root = host.attachShadow({ mode: 'open' });
