:host{display:block;width:100%;--surface:var(--ov-bg,#fff);--soft:var(--ov-soft,#f5f7fb);--text:var(--ov-text,#172033);--muted:var(--ov-muted,#697386);--line:var(--ov-line,#e4e8f0);--accent:var(--ov-accent,#5d55d6);font-family:ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;color:var(--text);-webkit-font-smoothing:antialiased}
*{box-sizing:border-box}
.card{position:relative;overflow:hidden;border:1px solid var(--line);border-radius:22px;background:var(--surface);box-shadow:0 16px 42px rgba(31,41,55,.09)}
.card:before{content:'';position:absolute;inset:0 0 auto;height:5px;background:linear-gradient(90deg,#6558d3,#e77cab 52%,#f3c95f)}
.inner{display:flex;align-items:center;justify-content:space-between;gap:28px;padding:29px 30px 27px}
.copy{min-width:0}.eyebrow{margin:0 0 7px;color:var(--accent);font-size:10px;font-weight:850;letter-spacing:.14em;text-transform:uppercase}
h2{margin:0;color:var(--text);font-size:clamp(22px,4vw,29px);line-height:1.15;letter-spacing:-.035em}
p{max-width:470px;margin:8px 0 0;color:var(--muted);font-size:13px;line-height:1.5}
.people{flex:0 0 min(42%,380px);min-width:245px;padding:16px 17px 14px;border:1px solid var(--line);border-radius:18px;background:var(--soft)}
vaadin-avatar-group{display:block;width:100%;--vaadin-avatar-background:var(--surface);--vaadin-avatar-text-color:var(--text);--vaadin-avatar-border-color:var(--surface);--vaadin-avatar-border-width:3px}
.meta{display:flex;align-items:center;gap:7px;margin-top:11px;color:var(--muted);font-size:10px;font-weight:750;letter-spacing:.035em;text-transform:uppercase}
.dot{width:7px;height:7px;border-radius:50%;background:#22a06b;box-shadow:0 0 0 3px color-mix(in srgb,#22a06b 17%,transparent)}
.empty{color:var(--muted);font-size:13px}
@media(max-width:680px){.inner{display:block;padding:26px 21px 22px}.people{width:100%;min-width:0;margin-top:21px}.copy p{max-width:none}}
@media(prefers-color-scheme:dark){:host{--surface:var(--ov-bg,#151c29);--soft:var(--ov-soft,#1c2635);--text:var(--ov-text,#edf1f7);--muted:var(--ov-muted,#a5afbf);--line:var(--ov-line,#303b4d);--accent:var(--ov-accent,#aaa2ff)}.card{box-shadow:0 18px 44px rgba(0,0,0,.3)}}
`;
const sheet = new CSSStyleSheet(); sheet.replaceSync(css); root.adoptedStyleSheets = [sheet];
const records = Array.isArray(data.items) ? data.items : [];
const size = Math.max(36, Math.min(72, Number(data.size) || 58));
const overlap = Math.max(0, Math.min(24, Number(data.overlap) || 14));
const maxVisible = Math.max(2, Math.round(Number(data.maxItemsVisible) || 5));
const title = typeof data.title === 'string' && data.title.trim() ? data.title.trim() : 'Project team';
const card = document.createElement('section'); card.className = 'card'; card.setAttribute('aria-label', title);
const inner = document.createElement('div'); inner.className = 'inner';
const copy = document.createElement('div'); copy.className = 'copy';
const eyebrow = document.createElement('div'); eyebrow.className = 'eyebrow'; eyebrow.textContent = 'Collaborators';
const heading = document.createElement('h2'); heading.textContent = title; copy.append(eyebrow, heading);
if (data.subtitle) { const sub = document.createElement('p'); sub.textContent = String(data.subtitle); copy.appendChild(sub); }
const people = document.createElement('div'); people.className = 'people';
if (records.length) {
  const group = document.createElement('vaadin-avatar-group');
  group.style.setProperty('--vaadin-avatar-size', `${size}px`); group.style.setProperty('--vaadin-avatar-group-overlap', `${overlap}px`);
  group.maxItemsVisible = maxVisible;
  group.items = records.map((item) => { const source = item && typeof item === 'object' ? item : {}; const next = {}; if (source.name != null) next.name = String(source.name); if (source.img) next.img = String(source.img); if (source.abbr != null) next.abbr = String(source.abbr); if (Number.isFinite(Number(source.colorIndex))) next.colorIndex = Number(source.colorIndex); return next; });
  people.appendChild(group);
  const meta = document.createElement('div'); meta.className = 'meta'; const dot = document.createElement('span'); dot.className = 'dot'; const label = document.createElement('span'); label.textContent = `${records.length} active collaborator${records.length === 1 ? '' : 's'}`; meta.append(dot, label); people.appendChild(meta);
} else { const empty = document.createElement('div'); empty.className = 'empty'; empty.textContent = 'Add people to form the group.'; people.appendChild(empty); }
inner.append(copy, people); card.appendChild(inner); root.appendChild(card); parent.appendChild(host);
await new Promise((resolve) => requestAnimationFrame(() => requestAnimationFrame(resolve)));

